package main.rice.test;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Objects;

/**
 * Represents a single test case containing a list of Python objects as arguments.
 */
public class TestCase {

    /**
     * The arguments for this test case.
     */
    private final List<APyObj> args;

    /**
     * Constructor for a TestCase; initializes its arguments to the input.
     *
     * @param args the arguments for this test case
     */
    public TestCase(List<APyObj> args) {
        this.args = args;
    }

    /**
     * Returns the arguments for this test case.
     *
     * @return the arguments for this test case
     */
    public List<APyObj> getArgs() {
        return this.args;
    }

    /**
     * Compares this to the input object by value.
     *
     * @param obj the object to compare against
     * @return true if this is equivalent by value to obj; false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof TestCase other)) {
            return false;
        }
        return this.args.equals(other.args);
    }

    /**
     * Computes a hash code based on this test case's arguments.
     *
     * @return the hash code for this test case
     */
    @Override
    public int hashCode() {
        return Objects.hash(this.args);
    }

    /**
     * Returns a string representation of this test case.
     *
     * @return a string representation of this test case
     */
    @Override
    public String toString() {
        return "TestCase(" + this.args + ")";
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyListObj;
import java.util.*;

/**
 * A node that generates Python list objects.
 * The exhaustive and random domains are lists of lengths.
 *
 * @param <InnerType> the type of elements contained in the lists
 */
public class PyListNode<InnerType extends APyObj> extends AIterablePyNode<PyListObj<InnerType>, InnerType> {

    /**
     * The child node that generates elements for the lists.
     */
    private final APyNode<InnerType> child;

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Constructor for a PyListNode; stores the child node.
     *
     * @param child the node that generates list elements
     */
    public PyListNode(APyNode<InnerType> child) {
        this.child = child;
    }

    /**
     * Gets the left child node (element generator).
     *
     * @return the element generator node
     */
    @Override
    public APyNode<?> getLeftChild() {
        return this.child;
    }

    /**
     * Generates all exhaustive list values based on the exhaustive domain.
     * For each length in the exhaustive domain, generates all combinations
     * of child values for that length.
     *
     * @return a set of all exhaustive lists
     */
    @Override
    public Set<PyListObj<InnerType>> genExVals() {
        Set<PyListObj<InnerType>> result = new HashSet<>();
        Set<InnerType> childVals = this.child.genExVals();
        List<InnerType> childList = new ArrayList<>(childVals);

        // For each length in the exhaustive domain
        for (Integer length : this.exDomain) {
            // Generate all combinations of length len from childList
            generateListCombinations(childList, length, 0, new ArrayList<>(), result);
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of elements with a given length.
     *
     * @param elements the elements to choose from
     * @param length the desired length of combinations
     * @param idx the current index
     * @param current the current combination being built
     * @param result the result set to add combinations to
     */
    private void generateListCombinations(List<InnerType> elements, int length, int idx,
                                         List<InnerType> current, Set<PyListObj<InnerType>> result) {
        if (current.size() == length) {
            result.add(new PyListObj<>(new ArrayList<>(current)));
            return;
        }

        if (idx >= elements.size()) {
            idx = 0; // Reset for next position
        }

        // For each element, try adding it to current
        for (InnerType elem : elements) {
            current.add(elem);
            generateListCombinations(elements, length, idx, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates a single random list value based on the random domain.
     *
     * @return a randomly generated list
     */
    @Override
    public PyListObj<InnerType> genRandVal() {
        int lenIdx = random.nextInt(this.ranDomain.size());
        int length = this.ranDomain.get(lenIdx);

        List<InnerType> listVal = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            listVal.add(this.child.genRandVal());
        }

        return new PyListObj<>(listVal);
    }
}

package main.rice.node;

import main.rice.obj.PyStringObj;
import java.util.*;

/**
 * A node that generates Python string objects.
 * The exhaustive and random domains are lists of lengths.
 * Strings are generated from a fixed set of allowed characters.
 */
public class PyStringNode extends AIterablePyNode<PyStringObj, main.rice.obj.PyCharObj> {

    /**
     * The set of allowed characters for generating strings.
     */
    private final String charset;

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Constructor for a PyStringNode; stores the charset.
     *
     * @param charset the string of allowed characters
     */
    public PyStringNode(String charset) {
        this.charset = charset;
    }

    /**
     * Generates all exhaustive string values based on the exhaustive domain.
     * For each length in the exhaustive domain, generates all combinations
     * of characters for that length.
     *
     * @return a set of all exhaustive strings
     */
    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new HashSet<>();

        // For each length in the exhaustive domain
        for (Integer length : this.exDomain) {
            // Generate all strings of this length
            generateStringCombinations(length, 0, new StringBuilder(), result);
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of characters with a given length.
     *
     * @param length the desired length
     * @param idx the current index
     * @param current the current string being built
     * @param result the result set to add strings to
     */
    private void generateStringCombinations(int length, int idx, StringBuilder current, Set<PyStringObj> result) {
        if (current.length() == length) {
            result.add(new PyStringObj(current.toString()));
            return;
        }

        // For each character, try adding it to current
        for (int i = 0; i < this.charset.length(); i++) {
            current.append(this.charset.charAt(i));
            generateStringCombinations(length, idx, current, result);
            current.deleteCharAt(current.length() - 1);
        }
    }

    /**
     * Generates a single random string value based on the random domain.
     *
     * @return a randomly generated string
     */
    @Override
    public PyStringObj genRandVal() {
        int lenIdx = random.nextInt(this.ranDomain.size());
        int length = this.ranDomain.get(lenIdx);

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < length; i++) {
            int charIdx = random.nextInt(this.charset.length());
            sb.append(this.charset.charAt(charIdx));
        }

        return new PyStringObj(sb.toString());
    }
}

package main.rice.node;

import main.rice.obj.AIterablePyObj;
import main.rice.obj.APyObj;

/**
 * An abstract class representing a node for iterable Python types
 * (list, set, tuple, or string) that contain elements generated by child nodes.
 *
 * @param <ValueType> the type of iterable Python object this node generates
 * @param <InnerType> the type of elements contained in the iterable
 */
public abstract class AIterablePyNode<ValueType extends AIterablePyObj<InnerType>, InnerType extends APyObj>
        extends APyNode<ValueType> {

    /**
     * Gets the left child node (element generator for lists/tuples/sets,
     * key generator for dicts, or character set for strings).
     *
     * @return the left child node, or null if not applicable
     */
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Gets the right child node (value generator for dicts only).
     *
     * @return the right child node, or null if not applicable
     */
    public APyNode<?> getRightChild() {
        return null;
    }
}

