        Set<InnerType> childVals = this.child.genExVals();
        List<InnerType> childList = new ArrayList<>(childVals);

        // For each length in the exhaustive domain
        for (Integer length : this.exDomain) {
            // Generate all combinations of length len from childList
            generateTupleCombinations(childList, length, 0, new ArrayList<>(), result);
        }

        return result;
