    /**
     * Helper method to generate all combinations of elements with a given length (with duplicates allowed).
     *
     * @param elements the elements to choose from
     * @param length the desired length of combinations
     * @param idx the current index
     * @param current the current combination being built
     * @param result the result set to add combinations to
     */
    private void generateTupleCombinations(List<InnerType> elements, int length, int idx,
                                          List<InnerType> current, Set<PyTupleObj<InnerType>> result) {
        if (current.size() == length) {
            result.add(new PyTupleObj<>(new ArrayList<>(current)));
            return;
        }

        // For each element, try adding it to current
        for (InnerType elem : elements) {
            current.add(elem);
            generateTupleCombinations(elements, length, idx, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates a single random tuple value based on the random domain.
     *
     * @return a randomly generated tuple
     */
    @Override
    public PyTupleObj<InnerType> genRandVal() {
        int lenIdx = random.nextInt(this.ranDomain.size());
        int length = this.ranDomain.get(lenIdx);

        List<InnerType> tupleVal = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            tupleVal.add(this.child.genRandVal());
        }

        return new PyTupleObj<>(tupleVal);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A node that generates Python dictionary objects.
 * The exhaustive and random domains are lists of sizes (number of key-value pairs).
 *
 * @param <KeyType> the type of keys in the dictionaries
 * @param <ValType> the type of values in the dictionaries
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends APyNode<PyDictObj<KeyType, ValType>> {

    /**
     * The child node that generates keys.
     */
    private final APyNode<KeyType> keyChild;

    /**
     * The child node that generates values.
     */
    private final APyNode<ValType> valChild;

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Constructor for a PyDictNode; stores the key and value nodes.
     *
     * @param keyChild the node that generates dictionary keys
     * @param valChild the node that generates dictionary values
     */
    public PyDictNode(APyNode<KeyType> keyChild, APyNode<ValType> valChild) {
        this.keyChild = keyChild;
        this.valChild = valChild;
    }

    /**
     * Gets the left child node (key generator).
     *
     * @return the key generator node
     */
    public APyNode<?> getLeftChild() {
        return this.keyChild;
    }

    /**
     * Gets the right child node (value generator).
     *
     * @return the value generator node
     */
    public APyNode<?> getRightChild() {
        return this.valChild;
    }

    /**
     * Generates all exhaustive dictionary values based on the exhaustive domain.
     * For each size in the exhaustive domain, generates all combinations
     * of key-value pairs for that size.
     *
     * @return a set of all exhaustive dictionaries
     */
    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();
        Set<KeyType> keyVals = this.keyChild.genExVals();
        Set<ValType> valVals = this.valChild.genExVals();
        List<KeyType> keyList = new ArrayList<>(keyVals);
        List<ValType> valList = new ArrayList<>(valVals);

        // Generate all key-value pairs
        List<Map.Entry<KeyType, ValType>> allPairs = new ArrayList<>();
        for (KeyType key : keyList) {
            for (ValType val : valList) {
                allPairs.add(new AbstractMap.SimpleEntry<>(key, val));
            }
        }

        // For each size in the exhaustive domain
        for (Integer size : this.exDomain) {
            // Generate all combinations of size that don't have duplicate keys
            generateDictCombinations(allPairs, keyList, size, 0, new HashMap<>(), result);
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of key-value pairs without duplicate keys.
     *
     * @param allPairs all possible key-value pairs
     * @param keyList all possible keys
     * @param size the desired number of pairs
     * @param startIdx the starting index for choosing pairs
     * @param current the current dictionary being built
     * @param result the result set to add dictionaries to
     */
    private void generateDictCombinations(List<Map.Entry<KeyType, ValType>> allPairs,
                                         List<KeyType> keyList, int size, int startIdx,
                                         Map<KeyType, ValType> current,
                                         Set<PyDictObj<KeyType, ValType>> result) {
        if (current.size() == size) {
            result.add(new PyDictObj<>(new HashMap<>(current)));
            return;
        }

        for (int i = startIdx; i < allPairs.size(); i++) {
            Map.Entry<KeyType, ValType> pair = allPairs.get(i);
            // Only add if key is not already in the map
            if (!current.containsKey(pair.getKey())) {
                current.put(pair.getKey(), pair.getValue());
                generateDictCombinations(allPairs, keyList, size, i + 1, current, result);
                current.remove(pair.getKey());
            }
        }
    }

    /**
     * Generates a single random dictionary value based on the random domain.
     *
     * @return a randomly generated dictionary
     */
    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        int sizeIdx = random.nextInt(this.ranDomain.size());
        int size = this.ranDomain.get(sizeIdx);

        Map<KeyType, ValType> dictVal = new HashMap<>();
        Set<KeyType> usedKeys = new HashSet<>();

        // Keep generating key-value pairs until we reach the desired size
        int attempts = 0;
        int maxAttempts = size * 100; // Prevent infinite loops
        while (dictVal.size() < size && attempts < maxAttempts) {
            KeyType key = this.keyChild.genRandVal();
            if (!usedKeys.contains(key)) {
                ValType val = this.valChild.genRandVal();
                dictVal.put(key, val);
                usedKeys.add(key);
            }
            attempts++;
        }

        return new PyDictObj<>(dictVal);
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.HashSet;
import java.util.Random;
import java.util.Set;

/**
 * A node that generates Python integer objects.
 * The exhaustive and random domains are lists of integers to generate.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Generates all exhaustive integer values based on the exhaustive domain.
     *
     * @return a set of all integers in the exhaustive domain as PyIntObj
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    /**
     * Generates a single random integer value based on the random domain.
     *
     * @return a randomly selected integer from the random domain as PyIntObj
     */
    @Override
    public PyIntObj genRandVal() {
        int idx = random.nextInt(this.ranDomain.size());
        return new PyIntObj(this.ranDomain.get(idx));
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PySetObj;
import java.util.*;

/**
 * A node that generates Python set objects.
 * The exhaustive and random domains are lists of sizes (number of elements).
 * Sets do not allow duplicates.
 *
 * @param <InnerType> the type of elements contained in the sets
 */
public class PySetNode<InnerType extends APyObj> extends AIterablePyNode<PySetObj<InnerType>, InnerType> {

    /**
     * The child node that generates elements for the sets.
     */
    private final APyNode<InnerType> child;

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Constructor for a PySetNode; stores the child node.
     *
     * @param child the node that generates set elements
     */
    public PySetNode(APyNode<InnerType> child) {
        this.child = child;
    }

    /**
     * Gets the left child node (element generator).
     *
     * @return the element generator node
     */
    @Override
    public APyNode<?> getLeftChild() {
        return this.child;
    }

    /**
     * Generates all exhaustive set values based on the exhaustive domain.
     * For each size in the exhaustive domain, generates all combinations
     * of child values for that size (without duplicates).
     *
     * @return a set of all exhaustive sets
     */
    @Override
    public Set<PySetObj<InnerType>> genExVals() {
        Set<PySetObj<InnerType>> result = new HashSet<>();
        Set<InnerType> childVals = this.child.genExVals();
        List<InnerType> childList = new ArrayList<>(childVals);

        // For each size in the exhaustive domain
        for (Integer size : this.exDomain) {
            // Generate all combinations of size from childList
            generateSetCombinations(childList, size, 0, new HashSet<>(), result);
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of elements without duplicates.
     *
     * @param elements the elements to choose from
     * @param size the desired size of combinations
     * @param startIdx the starting index for choosing elements
     * @param current the current combination being built
     * @param result the result set to add combinations to
     */
    private void generateSetCombinations(List<InnerType> elements, int size, int startIdx,
                                        Set<InnerType> current, Set<PySetObj<InnerType>> result) {
        if (current.size() == size) {
            result.add(new PySetObj<>(new HashSet<>(current)));
            return;
        }

        for (int i = startIdx; i < elements.size(); i++) {
            current.add(elements.get(i));
            generateSetCombinations(elements, size, i + 1, current, result);
            current.remove(elements.get(i));
        }
    }

    /**
     * Generates a single random set value based on the random domain.
     *
     * @return a randomly generated set
     */
    @Override
    public PySetObj<InnerType> genRandVal() {
        int sizeIdx = random.nextInt(this.ranDomain.size());
        int size = this.ranDomain.get(sizeIdx);

        Set<InnerType> setVal = new HashSet<>();
        // Generate random elements up to the desired size
        // Since we can't have duplicates, we need to keep generating until we have enough
        Set<InnerType> childVals = this.child.genExVals();
        if (setVal.size() < size && childVals.size() > 0) {
            List<InnerType> childList = new ArrayList<>(childVals);
            while (setVal.size() < size && setVal.size() < childList.size()) {
                int idx = random.nextInt(childList.size());
                setVal.add(childList.get(idx));
            }
        }

        return new PySetObj<>(setVal);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class representing a node that can generate Python objects.
 * Each node can generate exhaustive values (all possible values in a domain)
 * or random values (random samples from a domain).
 *
 * @param <ValueType> the type of Python object this node generates
 */
public abstract class APyNode<ValueType extends APyObj> {

    /**
     * The exhaustive domain - a list of integers representing configuration
     * for exhaustive value generation (e.g., list lengths to generate).
     */
    protected List<Integer> exDomain;

    /**
     * The random domain - a list of integers representing configuration
     * for random value generation (e.g., list lengths to generate randomly).
     */
    protected List<Integer> ranDomain;

    /**
     * Gets the exhaustive domain for this node.
     *
     * @return the exhaustive domain for this node
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param exDomain the exhaustive domain for this node
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Gets the random domain for this node.
     *
     * @return the random domain for this node
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param ranDomain the random domain for this node
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Generates all exhaustive values for this node based on the exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<ValueType> genExVals();

    /**
     * Generates a single random value for this node based on the random domain.
     *
     * @return a randomly generated value
     */
    public abstract ValueType genRandVal();

    /**
     * Gets the left child node (for nodes with children).
     *
     * @return the left child node, or null if not applicable
     */
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Gets the right child node (for nodes with two children).
     *
     * @return the right child node, or null if not applicable
     */
    public APyNode<?> getRightChild() {
        return null;
    }
}

package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * A generator that creates test cases by combining values from multiple argument nodes.
 * It can generate both exhaustive test cases (all combinations) and random test cases.
 */
public class BaseSetGenerator {

    /**
     * The nodes that generate argument values.
     */
    private final List<APyNode<?>> nodes;

    /**
     * The number of random test cases to generate in the combined base set.
     */
    private final int numRand;

    /**
     * Constructor for BaseSetGenerator; stores the nodes and random count.
     *
     * @param nodes the nodes that generate argument values
     * @param numRand the number of random test cases to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Generates all exhaustive test cases from the nodes.
     * This is the Cartesian product of all exhaustive values from each node.
     *
     * @return a set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        Set<TestCase> result = new HashSet<>();

        // Get exhaustive values from each node
        List<Set<APyObj>> allVals = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            allVals.add(new HashSet<>(node.genExVals()));
        }

        // Generate Cartesian product
        generateCartesianProduct(allVals, 0, new ArrayList<>(), result);

        return result;
    }

    /**
     * Helper method to generate the Cartesian product of value sets.
     *
     * @param allVals the list of value sets
     * @param nodeIdx the current node index
     * @param current the current combination being built
     * @param result the result set to add combinations to
     */
    private void generateCartesianProduct(List<Set<APyObj>> allVals, int nodeIdx,
                                         List<APyObj> current, Set<TestCase> result) {
        if (nodeIdx == allVals.size()) {
            result.add(new TestCase(new ArrayList<>(current)));
            return;
        }

        for (APyObj val : allVals.get(nodeIdx)) {
            current.add(val);
            generateCartesianProduct(allVals, nodeIdx + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates a specified number of random test cases from the nodes.
     *
     * @param numTests the number of random test cases to generate
     * @return a list of random test cases
     */
    public List<TestCase> genRandTests(int numTests) {
        List<TestCase> result = new ArrayList<>();

        for (int i = 0; i < numTests; i++) {
            List<APyObj> testArgs = new ArrayList<>();
