+     * @param result the result set to add combinations to
+     */
+    private void generateSetCombinations(List<InnerType> elements, int size, int startIdx,
+                                        Set<InnerType> current, Set<PySetObj<InnerType>> result) {
+        if (current.size() == size) {
+            result.add(new PySetObj<>(new HashSet<>(current)));
+            return;
+        }
+
+        for (int i = startIdx; i < elements.size(); i++) {
+            current.add(elements.get(i));
+            generateSetCombinations(elements, size, i + 1, current, result);
+            current.remove(elements.get(i));
+        }
+    }
+
+    /**
+     * Generates a single random set value based on the random domain.
+     *
+     * @return a randomly generated set
+     */
+    @Override
+    public PySetObj<InnerType> genRandVal() {
+        int sizeIdx = random.nextInt(this.ranDomain.size());
+        int size = this.ranDomain.get(sizeIdx);
+
+        Set<InnerType> setVal = new HashSet<>();
+        // Generate random elements up to the desired size
+        // Since we can't have duplicates, we need to keep generating until we have enough
+        Set<InnerType> childVals = this.child.genExVals();
+        if (setVal.size() < size && childVals.size() > 0) {
+            List<InnerType> childList = new ArrayList<>(childVals);
+            while (setVal.size() < size && setVal.size() < childList.size()) {
+                int idx = random.nextInt(childList.size());
+                setVal.add(childList.get(idx));
+            }
+        }
+
+        return new PySetObj<>(setVal);
+    }
+}
